const first = $input.all()[0]?.json ?? {};
const triggerMode = Object.keys(first).length > 0 ? 'schedule' : 'manual';
const promptVersion = $env.AI_DECISION_PROMPT_VERSION || 'block4-v1';
const modelName = $env.AI_DECISION_MODEL || 'gpt-5.5';
const providerName = ($env.AI_DECISION_PROVIDER || 'openai').toLowerCase();
const batchSize = Number($env.AI_DECISION_BATCH_SIZE || 10);
const retryDelayMinutes = Number($env.AI_DECISION_RETRY_DELAY_MINUTES || 30);
const startedAt = new Date().toISOString();
return [{
  json: {
    workflow_name: 'Analyze Opportunities',
    triggered_by: triggerMode,
    started_at_utc: startedAt,
    prompt_version: promptVersion,
    model_name: modelName,
    provider_name: providerName,
    batch_size: Number.isFinite(batchSize) && batchSize > 0 ? batchSize : 10,
    retry_delay_minutes: Number.isFinite(retryDelayMinutes) && retryDelayMinutes > 0 ? retryDelayMinutes : 30,
    profile_slug: $env.AI_DECISION_PROFILE_SLUG || '',
    lock_token: `${providerName}:${promptVersion}:${startedAt}`,
  },
}];

