const context = $('Init Decision Context').first().json;
const parseJson = (value) => {
  if (value && typeof value === 'object') {
    return value;
  }
  if (typeof value === 'string' && value.trim()) {
    return JSON.parse(value);
  }
  return {};
};
const opportunity = parseJson($json.opportunity_payload);
const profile = parseJson($json.profile_payload);
const outputSchema = {
  type: 'object',
  additionalProperties: false,
  required: [
    'summary',
    'is_recommended',
    'why_fit',
    'why_not_fit',
    'risks',
    'fit_score',
    'probability_to_win_score',
    'difficulty_score',
    'income_potential_score',
    'urgency_score',
    'skills_match_score',
    'decision_confidence_score'
  ],
  properties: {
    summary: { type: 'string' },
    is_recommended: { type: 'boolean' },
    why_fit: { type: 'array', items: { type: 'string' }, maxItems: 5 },
    why_not_fit: { type: 'array', items: { type: 'string' }, maxItems: 5 },
    risks: { type: 'array', items: { type: 'string' }, maxItems: 5 },
    fit_score: { type: 'number', minimum: 0, maximum: 100 },
    probability_to_win_score: { type: 'number', minimum: 0, maximum: 100 },
    difficulty_score: { type: 'number', minimum: 0, maximum: 100 },
    income_potential_score: { type: 'number', minimum: 0, maximum: 100 },
    urgency_score: { type: 'number', minimum: 0, maximum: 100 },
    skills_match_score: { type: 'number', minimum: 0, maximum: 100 },
    decision_confidence_score: { type: 'number', minimum: 0, maximum: 100 }
  }
};
const systemPrompt = [
  'You are the AI Decision Engine for AI Career Agent.',
  'Analyze one opportunity against one user intelligence profile.',
  'Use only the provided opportunity data and profile context.',
  'Return strict JSON that matches the supplied schema.',
  'Scoring rules:',
  '- 0 means worst possible alignment or signal.',
  '- 100 means best possible alignment or signal.',
  '- High difficulty means harder execution.',
  '- High probability_to_win means the user has a strong chance to secure the opportunity.',
  '- High income_potential should reflect the likely business value for this specific user.',
  '- If evidence is missing, stay conservative and reflect uncertainty in decision_confidence_score and the narrative arrays.',
  'Do not add keys outside the schema.'
].join('\n');
const userPrompt = JSON.stringify({ opportunity, user_intelligence_profile: profile }, null, 2);
const inputSnapshot = {
  workflow_name: context.workflow_name,
  prompt_version: context.prompt_version,
  provider_name: context.provider_name,
  model_name: context.model_name,
  opportunity,
  user_intelligence_profile: profile,
};
return [{
  json: {
    job_id: $json.job_id,
    opportunity_id: $json.opportunity_id,
    user_intelligence_profile_id: $json.user_intelligence_profile_id,
    profile_slug: $json.profile_slug,
    provider_name: context.provider_name,
    model_name: context.model_name,
    prompt_version: context.prompt_version,
    retry_delay_minutes: context.retry_delay_minutes,
    input_snapshot: inputSnapshot,
    openai_request: {
      model: context.model_name,
      temperature: 0.2,
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt }
      ],
      response_format: {
        type: 'json_schema',
        json_schema: {
          name: 'opportunity_decision',
          strict: true,
          schema: outputSchema
        }
      }
    }
  }
}];

const source = $('Build OpenAI Request').item.json;
const payload = $json ?? {};
const parseJsonCandidate = (value) => {
  if (!value) {
    return null;
  }
  if (typeof value === 'object') {
    return value;
  }
  if (typeof value !== 'string') {
    return null;
  }
  const trimmed = value.trim();
  if (!trimmed) {
    return null;
  }
  try {
    return JSON.parse(trimmed);
  } catch (error) {
    const start = trimmed.indexOf('{');
    const end = trimmed.lastIndexOf('}');
    if (start !== -1 && end !== -1 && end > start) {
      try {
        return JSON.parse(trimmed.slice(start, end + 1));
      } catch (nestedError) {
        return null;
      }
    }
  }
  return null;
};
const collectTextCandidates = (value, sink) => {
  if (!value) {
    return;
  }
  if (typeof value === 'string') {
    sink.push(value);
    return;
  }
  if (Array.isArray(value)) {
    for (const item of value) {
      collectTextCandidates(item, sink);
    }
    return;
  }
  if (typeof value === 'object') {
    if (typeof value.text === 'string') {
      sink.push(value.text);
    }
    if (typeof value.content === 'string') {
      sink.push(value.content);
    }
    if (Array.isArray(value.content)) {
      collectTextCandidates(value.content, sink);
    }
    if (Array.isArray(value.output)) {
      collectTextCandidates(value.output, sink);
    }
  }
};
if (payload.error) {
  return [{
    json: {
      ...source,
      has_error: true,
      error_message: payload.error.message || 'OpenAI request failed.',
      error_details: {
        error: payload.error,
      },
      llm_response_id: payload.id || null,
    },
  }];
}
const candidates = [];
collectTextCandidates(payload.output_text, candidates);
collectTextCandidates(payload.choices?.[0]?.message?.content, candidates);
collectTextCandidates(payload.output, candidates);
const parsed = candidates.map(parseJsonCandidate).find(Boolean) || parseJsonCandidate(payload.choices?.[0]?.message?.parsed);
if (!parsed) {
  return [{
    json: {
      ...source,
      has_error: true,
      error_message: 'OpenAI response did not contain a valid JSON decision payload.',
      error_details: {
        response_id: payload.id || null,
        response_preview: JSON.stringify(payload).slice(0, 4000),
      },
      llm_response_id: payload.id || null,
    },
  }];
}
return [{
  json: {
    ...source,
    has_error: false,
    analysis_json: parsed,
    llm_response_id: payload.id || null,
    model_name: payload.model || source.model_name,
  },
}];
